import React from 'react';
import { Link } from 'react-router-dom';

export default function NavBar(){
  return (
    <nav style={{background:'#0b74da',padding:10,color:'#fff'}}>
      <div style={{display:'flex',gap:12}}>
        <Link to="/dashboard" style={{color:'#fff'}}>Dashboard</Link>
        <Link to="/inventory" style={{color:'#fff'}}>Inventory</Link>
        <Link to="/orders" style={{color:'#fff'}}>Orders</Link>
        <Link to="/customers" style={{color:'#fff'}}>Customers</Link>
        <Link to="/suppliers" style={{color:'#fff'}}>Suppliers</Link>
        <Link to="/reports" style={{color:'#fff'}}>Reports</Link>
        <Link to="/signup" style={{color:'#fff',marginLeft:'auto'}}>Sign Up</Link>
        <Link to="/profile" style={{color:'#fff'}}>Profile</Link>
      </div>
    </nav>
  )
}
